import { createContext, useContext, useMemo, useState, useEffect, useRef } from "react";
import { jwtDecode } from "jwt-decode";
import api from "./api";

const AuthContext = createContext(null);

/** ===== Helpers lưu token theo “Ghi nhớ” ===== **/
const STORAGE_KEY = "access_token";

function getStorages() {
    return {
        get() {
            return sessionStorage.getItem(STORAGE_KEY) || localStorage.getItem(STORAGE_KEY);
        },
        set(token, remember) {
            sessionStorage.removeItem(STORAGE_KEY);
            localStorage.removeItem(STORAGE_KEY);
            if (remember) localStorage.setItem(STORAGE_KEY, token);
            else sessionStorage.setItem(STORAGE_KEY, token);
        },
        remove() {
            sessionStorage.removeItem(STORAGE_KEY);
            localStorage.removeItem(STORAGE_KEY);
        },
    };
}

function toUpperArray(v) {
    if (v == null) return [];
    if (Array.isArray(v)) return v.map((x) => String(x).toUpperCase());
    if (typeof v === "string")
        return v
            .split(/[,\s]+/)
            .filter(Boolean)
            .map((x) => x.toUpperCase());
    return [String(v).toUpperCase()];
}

/** Rút role gốc + permissions từ JWT payload */
function normalizeUserFromJwt(payload) {
    const bag = new Set();
    ["authorities", "permissions", "perms", "scopes", "scope", "roles", "role"].forEach((k) => {
        toUpperArray(payload[k]).forEach((x) => bag.add(x));
    });

    let baseRole = String(payload.baseRole || payload.role || "")
        .toUpperCase()
        .replace(/^ROLE_/, "");
    if (!baseRole) {
        const hit = [...bag].find((x) => x.startsWith("ROLE_"));
        if (hit) baseRole = hit.slice(5);
    }
    if (!baseRole) baseRole = "SALES";

    const perms = [...bag].filter((x) => !x.startsWith("ROLE_") && x !== baseRole);

    return {
        id: payload.userId || payload.id,
        username: payload.sub || payload.username,
        role: baseRole,      // ADMIN | SALES | ACCOUNTANT
        roles: [baseRole],   // giữ tương thích ngược
        perms,               // ví dụ: ["CONTRACT_READ","CONTRACT_WRITE"]
        raw: payload,
    };
}

function parseExpMs(token) {
    try {
        const p = jwtDecode(token);
        return typeof p?.exp === "number" ? p.exp * 1000 : null;
    } catch {
        return null;
    }
}

export function AuthProvider({ children }) {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);
    const logoutTimerRef = useRef(null);

    const stor = getStorages();

    const clearLogoutTimer = () => {
        if (logoutTimerRef.current) {
            clearTimeout(logoutTimerRef.current);
            logoutTimerRef.current = null;
        }
    };

    const scheduleAutoLogout = (token) => {
        clearLogoutTimer();
        const expMs = parseExpMs(token);
        if (!expMs) return;
        const delay = Math.max(0, expMs - Date.now());
        if (delay === 0) return doLogout(true);
        logoutTimerRef.current = setTimeout(() => doLogout(true), delay);
    };

    const doLogout = (silent = false) => {
        clearLogoutTimer();
        stor.remove();
        setUser(null);
        if (!silent) {
            // window.location.assign('/login');
        }
        try {
            localStorage.setItem("__logout_pulse__", String(Date.now()));
            setTimeout(() => localStorage.removeItem("__logout_pulse__"), 0);
        } catch {}
    };

    useEffect(() => {
        const t = stor.get();
        if (t) {
            try {
                const expMs = parseExpMs(t);
                if (expMs && expMs <= Date.now()) {
                    doLogout(true);
                } else {
                    const p = jwtDecode(t);
                    setUser(normalizeUserFromJwt(p));
                    scheduleAutoLogout(t);
                }
            } catch {
                doLogout(true);
            }
        }
        setLoading(false);
        return clearLogoutTimer;
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    const login = async (username, password, remember = false) => {
        const { data } = await api.post("/api/auth/login", { username, password });
        const token = data.token || data.accessToken;
        if (!token) throw new Error("Thiếu access token từ server");
        stor.set(token, !!remember);
        const p = jwtDecode(token);
        setUser(normalizeUserFromJwt(p));
        scheduleAutoLogout(token);
    };

    const logout = () => doLogout(false);

    const value = useMemo(() => ({ user, loading, login, logout }), [user, loading]);
    return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export const useAuth = () => useContext(AuthContext);

/** Kiểm tra role gốc */
export const hasRole = (user, ...roles) => {
    const ur = String(user?.role || "").toUpperCase();
    return roles.some((r) => ur === String(r).toUpperCase());
};

/** Kiểm tra permission chi tiết (ADMIN luôn true) */
export const can = (user, ...perms) => {
    if (hasRole(user, "ADMIN")) return true;
    const set = new Set((user?.perms || []).map((x) => String(x).toUpperCase()));
    return perms.some((p) => set.has(String(p).toUpperCase()));
};
